// Recuperar chunks de Pinecone
const matches = $('HTTP: Busqueda Semantica en Pinecone').first().json.matches || [];
const historiaClinica = $('Postgres: Historia Clinica del Paciente').first().json || {};
const consulta = $('Set: Usar Texto Directo').first().json;

// Filtrar chunks con score relevante
const chunksRelevantes = matches
  .filter(m => m.score >= 0.72)
  .map((m, i) => `[Fuente ${i+1}: ${m.metadata?.fuente || 'Protocolo Clinico'} — Seccion: ${m.metadata?.seccion || 'General'}]\n${m.metadata?.text || ''}`);

const avgScore = matches.length > 0 
  ? matches.reduce((s, m) => s + m.score, 0) / matches.length 
  : 0;

// Construir contexto clinico
const contextoRAG = chunksRelevantes.length > 0
  ? chunksRelevantes.join('\n\n---\n\n')
  : 'No se encontraron protocolos especificos. Responder con informacion general y recomendar consulta medica.';

// Historia clinica anonimizada
const historiaTexto = historiaClinica.diagnosticos_previos
  ? `Antecedentes conocidos: ${historiaClinica.diagnosticos_previos}\nMedicacion activa: ${historiaClinica.medicacion_activa || 'ninguna registrada'}\nAlergias: ${historiaClinica.alergias || 'sin registro'}`
  : 'Sin historia clinica previa en el sistema.';

return [{
  json: {
    ...consulta,
    contexto_rag: contextoRAG,
    historia_clinica: historiaTexto,
    rag_chunks_count: chunksRelevantes.length,
    rag_avg_score: Math.round(avgScore * 1000) / 1000,
    fuentes_citadas: matches.map(m => m.metadata?.fuente).filter(Boolean).join(', ')
  }
}];

const agentOutput = $input.first().json;
const inputData = $('Code: Construir Contexto Clinico RAG').first().json;

// Calcular metricas de la respuesta
const respuestaTexto = agentOutput.output || '';
const tieneDisclaimer = respuestaTexto.toLowerCase().includes('medico') || 
                        respuestaTexto.toLowerCase().includes('consultar');

// Preparar para log en Postgres
return [{
  json: {
    patient_hash: inputData.body?.patient_hash || inputData.patient_hash,
    canal: inputData.body?.canal || 'unknown',
    consulta_id: inputData.body?.consulta_id,
    workflow_id: 'WF2',
    event_type: 'rag_response_generated',
    rag_chunks_count: inputData.rag_chunks_count,
    rag_avg_score: inputData.rag_avg_score,
    fuentes_citadas: inputData.fuentes_citadas,
    tiene_disclaimer_medico: tieneDisclaimer,
    respuesta_texto: respuestaTexto.substring(0, 500),
    respuesta_completa: respuestaTexto,
    timestamp: new Date().toISOString()
  }
}];
